mapper.select:


    and kb_id = #{kbId}

        and doc_logical_key like concat('%', #{docLogicalKey}, '%')

    and file_ext = #{fileExt}

        and date_format(update_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


        and date_format(update_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')


order by update_time desc, id desc
